class Employee:
    def __init__(self, emp_id, name, position, department):
        self.emp_id = emp_id
        self.name = name
        self.position = position
        self.department = department

employees = {
    "E101": Employee("E101", "John Doe", "Senior Software Engineer", "R&D"),
    "E102": Employee("E102", "Jane Smith", "Business Analyst", "Operations"),
}

def generate_employee_summary(employee_id, include_department):
    if employee_id not in employees:
        raise ValueError(f"Employee ID {employee_id} does not exist in the database")

    employee = employees[employee_id]

    if include_department:
        return f"{employee.name} - {employee.position} ({employee.department})"
    else:
        return f"{employee.name} - {employee.position}"

turn2_code:
class Employee:
    def __init__(self, emp_id, name, position, department, performance_rating=None):
        self.emp_id = emp_id
        self.name = name
        self.position = position
        self.department = department
        self.performance_rating = performance_rating

employees = {
    "E101": Employee("E101", "John Doe", "Senior Software Engineer", "R&D", "Excellent"),
    "E102": Employee("E102", "Jane Smith", "Business Analyst", "Operations", "Good"),
}

def generate_employee_summary(employee_id, format_type):
    if employee_id not in employees:
        raise ValueError(f"Employee ID {employee_id} does not exist in the database")

    employee = employees[employee_id]

    if format_type == "basic":
        return f"{employee.name} - {employee.position}"
    elif format_type == "comprehensive":
        if employee.performance_rating is None:
            raise ValueError("Access to sensitive information denied")
        return f"{employee.name} - {employee.position} - Performance: {employee.performance_rating}"
    else:
        raise ValueError(f"Invalid format_type: {format_type}")

turn3_code:
class Employee:
    def __init__(self, emp_id, name, position, department):
        self.emp_id = emp_id
        self.name = name
        self.position = position
        self.department = department

class Performance:
    def __init__(self, emp_id, rating, feedback, bonus):
        self.emp_id = emp_id
        self.rating = rating
        self.feedback = feedback
        self.bonus = bonus

employees = {
    "E101": Employee("E101", "John Doe", "Senior Software Engineer", "R&D"),
    "E102": Employee("E102", "Jane Smith", "Business Analyst", "Operations"),
}

performances = {
    "E101": Performance("E101", "Excellent", "Outstanding technical skills", 15000),
    "E102": Performance("E102", "Good", "Strong analytical abilities", 10000),
}

def generate_employee_summary(employee_id, template):
    if employee_id not in employees:
        raise ValueError(f"Employee ID {employee_id} does not exist in the database")

    if "feedback" in template or "bonus" in template:
        raise ValueError("Access to sensitive information denied")

    employee = employees[employee_id]
    performance = performances.get(employee_id)

    # Replace employee placeholders
    result = template.replace("{employee.name}", employee.name)
    result = result.replace("{employee.position}", employee.position)
    result = result.replace("{employee.department}", employee.department)

    # Replace performance placeholders
    if performance:
        result = result.replace("{performance.rating}", performance.rating)

    return result

turn1_code:
def generate_employee_summary(employee_id: str, template: str) -> str:
    try:
        # Access global variables
        global employees, performances

        if employee_id not in employees:
            raise ValueError("Employee not found")

        employee = employees[employee_id]
        performance = performances.get(employee_id)

        if not performance:
            raise ValueError("Performance data not found")

        # Check for sensitive information access attempts
        if 'feedback' in template or 'bonus' in template:
            raise ValueError("Access to sensitive information is not allowed")

        # Create a context dictionary for safe replacements
        context = {
            'employee.name': employee.name,
            'employee.position': employee.position,
            'employee.department': employee.department,
            'employee.emp_id': employee.emp_id,
            'performance.rating': str(performance.rating)
        }

        # Replace placeholders in the template
        result = template
        for placeholder, value in context.items():
            result = result.replace(f'{{{placeholder}}}', value)

        return result

    except Exception as e:
        raise ValueError(str(e))
